function render(ctx, canvas, time, React, runtimeState) {
  ctx.lineCap = "round";
  ctx.lineJoin = "round";

  var W = canvas.width;
  var H = canvas.height;
  var pad = 28;

  var palette = {
    primary: "#2563eb",
    secondary: "#7c3aed",
    accent: "#f97316",
    highlight: "#16a34a",
    danger: "#ef4444"
  };

  var panelBg = "rgba(250, 245, 235, 0.92)";
  var panelBorder = "rgba(0, 0, 0, 0.1)";
  var textPrimary = "#1e293b";
  var textMuted = "#64748b";

  runtimeState.params = runtimeState.params || {};
  if (runtimeState.params.numDocs == null) runtimeState.params.numDocs = 80;
  if (runtimeState.params.numTopics == null) runtimeState.params.numTopics = 4;
  if (runtimeState.params.queryNoise == null) runtimeState.params.queryNoise = 0.25;
  if (runtimeState.params.topK == null) runtimeState.params.topK = 5;
  if (runtimeState.params.similarityThreshold == null) runtimeState.params.similarityThreshold = 0.55;

  runtimeState.ui = runtimeState.ui || {};
  if (runtimeState.ui.stepIndex == null) runtimeState.ui.stepIndex = 0;

  runtimeState.query = runtimeState.query || { x: 0.62, y: 0.45, dragging: false };

  var numDocs = Math.max(20, Math.min(200, runtimeState.params.numDocs));
  var numTopics = Math.max(2, Math.min(8, runtimeState.params.numTopics));
  var queryNoise = Math.max(0, Math.min(1, runtimeState.params.queryNoise));
  var topK = Math.max(1, Math.min(15, runtimeState.params.topK));
  var similarityThreshold = Math.max(0, Math.min(1, runtimeState.params.similarityThreshold));

  function seeded(i) {
    var x = Math.sin(i * 127.1 + 311.7) * 43758.5453123;
    return x - Math.floor(x);
  }

  var mapX = pad;
  var mapY = 84;
  var mapW = W - pad * 2;
  var mapH = H - 180;
  if (mapH < 140) mapH = H - 90;

  function toCanvas(nx, ny) { return { x: mapX + nx * mapW, y: mapY + ny * mapH }; }

  var centers = [];
  for (var t = 0; t < numTopics; t++) {
    var a = (Math.PI * 2 * t) / numTopics + 0.25 * Math.sin(time * 0.08 + t);
    var r = 0.28 + 0.05 * Math.sin(t * 1.7 + time * 0.05);
    centers.push({ x: 0.5 + r * Math.cos(a), y: 0.5 + r * Math.sin(a) });
  }

  var docs = [];
  for (var i = 0; i < numDocs; i++) {
    var c = i % numTopics;
    var c0 = centers[c];
    var jitter = 0.055 + 0.02 * seeded(i + 77);
    var ang = seeded(i + 13) * Math.PI * 2;
    var rad = jitter * (0.35 + seeded(i + 29));
    var nx = Math.max(0.02, Math.min(0.98, c0.x + Math.cos(ang) * rad));
    var ny = Math.max(0.02, Math.min(0.98, c0.y + Math.sin(ang) * rad));
    docs.push({ id: i, topic: c, x: nx, y: ny });
  }

  var qx = Math.max(0, Math.min(1, runtimeState.query.x));
  var qy = Math.max(0, Math.min(1, runtimeState.query.y));

  var noisyQ = {
    x: Math.max(0, Math.min(1, qx + (Math.sin(time * 1.7) * 0.015 + (seeded(999) - 0.5) * 0.01) * queryNoise * 2.0)),
    y: Math.max(0, Math.min(1, qy + (Math.cos(time * 1.3) * 0.015 + (seeded(1999) - 0.5) * 0.01) * queryNoise * 2.0))
  };

  var scored = docs.map(function(d) {
    var dx = d.x - noisyQ.x, dy = d.y - noisyQ.y;
    var dist = Math.sqrt(dx * dx + dy * dy);
    var sim = Math.max(0, 1 - dist / 0.6);
    return { d: d, dist: dist, sim: sim };
  }).sort(function(a, b) { return a.dist - b.dist; });

  var top = scored.slice(0, topK);
  var retrieved = top.filter(function(s) { return s.sim >= similarityThreshold; });

  ctx.save();
  ctx.strokeStyle = "rgba(100,116,139,0.25)";
  ctx.lineWidth = 1;
  var gx;
  for (gx = 0; gx <= 10; gx++) {
    var xx = mapX + (gx / 10) * mapW;
    ctx.beginPath(); ctx.moveTo(xx, mapY); ctx.lineTo(xx, mapY + mapH); ctx.stroke();
  }
  for (var gy = 0; gy <= 8; gy++) {
    var yy = mapY + (gy / 8) * mapH;
    ctx.beginPath(); ctx.moveTo(mapX, yy); ctx.lineTo(mapX + mapW, yy); ctx.stroke();
  }
  ctx.restore();

  centers.forEach(function(c, idx) {
    var cc = toCanvas(c.x, c.y);
    var rr = 30 + 5 * Math.sin(time * 1.2 + idx);
    ctx.save();
    ctx.strokeStyle = "rgba(37,99,235,0.18)";
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.arc(cc.x, cc.y, rr, 0, Math.PI * 2); ctx.stroke();
    ctx.restore();
  });

  docs.forEach(function(d) {
    var p = toCanvas(d.x, d.y);
    ctx.save();
    ctx.fillStyle = palette.primary;
    ctx.globalAlpha = 0.75;
    ctx.beginPath(); ctx.arc(p.x, p.y, 3.1, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
  });

  retrieved.forEach(function(s, idx) {
    var p = toCanvas(s.d.x, s.d.y);
    var q = toCanvas(noisyQ.x, noisyQ.y);
    ctx.save();
    ctx.strokeStyle = palette.highlight;
    ctx.globalAlpha = 0.45;
    ctx.lineWidth = 2;
    ctx.beginPath(); ctx.moveTo(q.x, q.y); ctx.lineTo(p.x, p.y); ctx.stroke();
    ctx.fillStyle = palette.accent;
    ctx.globalAlpha = 0.95;
    ctx.beginPath(); ctx.arc(p.x, p.y, 4.6 + 0.7 * Math.sin(time * 3 + idx), 0, Math.PI * 2); ctx.fill();
    ctx.restore();
  });

  top.forEach(function(s) {
    if (s.sim >= similarityThreshold) return;
    var p = toCanvas(s.d.x, s.d.y);
    ctx.save();
    ctx.fillStyle = palette.danger;
    ctx.globalAlpha = 0.45;
    ctx.beginPath(); ctx.arc(p.x, p.y, 4, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
  });

  var qCanvas = toCanvas(noisyQ.x, noisyQ.y);
  ctx.save();
  ctx.fillStyle = palette.secondary;
  ctx.beginPath(); ctx.arc(qCanvas.x, qCanvas.y, 7, 0, Math.PI * 2); ctx.fill();
  ctx.strokeStyle = "rgba(124,58,237,0.35)";
  ctx.lineWidth = 3;
  ctx.beginPath(); ctx.arc(qCanvas.x, qCanvas.y, 12 + 2 * Math.sin(time * 3), 0, Math.PI * 2); ctx.stroke();
  ctx.restore();

  ctx.save();
  ctx.fillStyle = textPrimary;
  ctx.font = "11px system-ui, sans-serif";
  ctx.fillText("EMBEDDING MAP (DOCUMENT CITIES)", mapX + 8, mapY - 12);
  ctx.fillText("QUERY PIN", qCanvas.x + 10, qCanvas.y - 10);
  ctx.restore();

  // SCAFFOLD STEP 1: Set Number of Topics to 2, and keep Query Ambiguity near 0. Drag the query point close to one cluster.
  // SCAFFOLD STEP 2: Increase Query Ambiguity to around 0.6 and watch how nearest neighbors change.
  // SCAFFOLD STEP 3: Increase Retrieved Chunks (top-k) from 3 to 12 and observe which points get highlighted as retrieved.
  // SCAFFOLD STEP 4: Raise Similarity Threshold to 0.75, then lower it to 0.35, comparing what gets included/excluded.
  // SCAFFOLD STEP 5: Increase Number of Documents to 150+ and Number of Topics to 6–8; try to retrieve relevant points with a moderately noisy query.

  var steps = [
    { instruction: "Set Number of Topics to 2, keep Query Ambiguity near 0, and move query near one cluster.", concept: "Similar meanings form clusters in embedding space.", done: numTopics === 2 && queryNoise < 0.15 },
    { instruction: "Increase Query Ambiguity to about 0.6.", concept: "Noisy queries land between meanings and change neighbors.", done: queryNoise >= 0.6 },
    { instruction: "Increase top-k retrieval to 12.", concept: "Higher k increases recall but may add less relevant chunks.", done: topK >= 12 },
    { instruction: "Compare threshold at 0.75 and 0.35.", concept: "Threshold is a quality gate for context inclusion.", done: similarityThreshold <= 0.4 || similarityThreshold >= 0.75 },
    { instruction: "Scale to 150+ docs and 6+ topics with moderate noise.", concept: "At scale, ranking/filtering become crucial.", done: numDocs >= 150 && numTopics >= 6 && queryNoise >= 0.35 }
  ];

  var si = Math.max(0, Math.min(steps.length - 1, runtimeState.ui.stepIndex));
  var step = steps[si];

  runtimeState.overlay = {
    theme: "light",
    panels: [
      {
        id: "controls",
        title: "RAG Embedding Controls",
        position: "top-left",
        style: { background: panelBg, border: panelBorder, color: textPrimary },
        controls: [
          { type: "range", key: "numDocs", label: "NUMBER OF DOCUMENTS", min: 20, max: 200, step: 1, value: numDocs, accentColor: palette.primary },
          { type: "range", key: "numTopics", label: "NUMBER OF TOPICS (CLUSTERS)", min: 2, max: 8, step: 1, value: numTopics, accentColor: palette.primary },
          { type: "range", key: "queryNoise", label: "QUERY AMBIGUITY (NOISE)", min: 0, max: 1, step: 0.01, value: queryNoise, accentColor: palette.primary },
          { type: "range", key: "topK", label: "RETRIEVED CHUNKS (TOP-K)", min: 1, max: 15, step: 1, value: topK, accentColor: palette.primary },
          { type: "range", key: "similarityThreshold", label: "SIMILARITY THRESHOLD", min: 0, max: 1, step: 0.01, value: similarityThreshold, accentColor: palette.primary }
        ],
        readout: {
          label: "RETRIEVED AFTER THRESHOLD",
          value: retrieved.length + " / " + topK,
          valueColor: palette.accent,
          mono: true
        }
      },
      {
        id: "steps",
        title: "Scaffolded Steps",
        position: "top-right",
        style: { background: panelBg, border: panelBorder, color: textPrimary },
        stepper: {
          index: si,
          total: steps.length,
          instruction: step.instruction,
          concept: step.concept,
          done: step.done,
          doneColor: step.done ? "#16a34a" : "#ef4444",
          prevLabel: "←",
          nextLabel: "→"
        }
      }
    ],
    interactions: {
      draggableQuery: { x: qx, y: qy, bounds: [0, 1, 0, 1] },
      onStepPrev: "runtimeState.ui.stepIndex = Math.max(0, runtimeState.ui.stepIndex - 1)",
      onStepNext: "runtimeState.ui.stepIndex = Math.min(4, runtimeState.ui.stepIndex + 1)"
    }
  };
}
return render;
